mapper.select:
SELECT reservation_id, facility_name, reserver_name, reservation_date, start_time, end_time, purpose, status, reg_date FROM erp_reservation
AND (facility_name LIKE '%' || #{keyword} || '%' OR reserver_name LIKE '%' || #{keyword} || '%')
ORDER BY reservation_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT vehicle_id, vehicle_name, plate_number, driver, capacity, status FROM erp_vehicle
AND (vehicle_name LIKE '%' || #{keyword} || '%' OR driver LIKE '%' || #{keyword} || '%')
ORDER BY vehicle_name LIMIT #{limit} OFFSET #{offset}

SELECT inventory_id, item_name, category, quantity, unit, location, status, reg_date FROM erp_inventory
AND (item_name LIKE '%' || #{keyword} || '%' OR category LIKE '%' || #{keyword} || '%')
ORDER BY category, item_name LIMIT #{limit} OFFSET #{offset}

SELECT maintenance_id, facility_name, title, maintenance_date, description, cost, status, reg_date FROM erp_maintenance
AND (facility_name LIKE '%' || #{keyword} || '%' OR title LIKE '%' || #{keyword} || '%')
ORDER BY maintenance_date DESC LIMIT #{limit} OFFSET #{offset}
